  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');

  const save = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const r = await authApi.updateProfile(form);
      updateUser(r.data);
      setMsg('Profile updated!'); setTimeout(() => setMsg(''), 3000);
    } catch { setMsg('Update failed'); setTimeout(() => setMsg(''), 3000); }
